using System.Net;
using System.ComponentModel;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Chat client ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tools ---
using var httpClient = new HttpClient { Timeout = TimeSpan.FromSeconds(15) };
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var webTools = new WebTools(httpClient);
var notebook = new Notebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webTools.SearchWeb),
    AIFunctionFactory.Create(webTools.FetchWebPage),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// --- Agent ---
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "Researches topics using web search and structured note-taking.",
        ChatOptions = new ChatOptions
        {
            Instructions = """
                You are a thorough research assistant. When given a topic:
                1. Search the web with multiple varied queries to cover different aspects of the topic.
                2. Fetch relevant web pages to get detailed information.
                3. Save key findings as notes with descriptive titles — include facts, data, and source URLs.
                4. After gathering enough information, review your notes and write a comprehensive,
                   well-organized summary citing your sources.
                Be factual. Prefer primary sources. Clearly distinguish established facts from speculation.
                """,
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = tools,
        },
    });

// --- Main loop ---
Console.WriteLine("🔍 Research Agent");
Console.WriteLine("Enter a topic to research, or 'quit' to exit.");
Console.WriteLine();

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine($"\nResearching: {topic}\n");
    notebook.Clear();

    try
    {
        var session = await agent.CreateSessionAsync(default);
        var prompt = $"Research this topic thoroughly: {topic}";

        await foreach (var update in agent.RunStreamingAsync(prompt, session))
        {
            foreach (var message in update.Messages)
            {
                if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
                    Console.Write(message.Text);
            }
        }

        Console.WriteLine("\n");
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\nError: {ex.Message}\n");
    }
}

