// Tool implementations
// =============================================================================

sealed class WebTools(HttpClient http)
{
    [Description("Searches the web for information on a query. Returns results with titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var json = await http.GetStringAsync(url, cancellationToken);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;
            var results = new List<string>();

            var abstractText = root.GetProperty("AbstractText").GetString();
            if (!string.IsNullOrEmpty(abstractText))
            {
                var source = root.GetProperty("AbstractSource").GetString();
                var abstractUrl = root.GetProperty("AbstractURL").GetString();
                results.Add($"[{source}] {abstractText}\nURL: {abstractUrl}");
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(8))
                {
                    if (topic.TryGetProperty("Text", out var text)
                        && topic.TryGetProperty("FirstURL", out var firstUrl))
                    {
                        results.Add($"- {text.GetString()}\n  URL: {firstUrl.GetString()}");
                    }
                }
            }

            return results.Count > 0
                ? $"Search results for '{query}':\n\n{string.Join("\n\n", results)}"
                : $"No results found for '{query}'. Try different search terms.";
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    [Description("Fetches and extracts the text content from a web page at the given URL.")]
    public async Task<string> FetchWebPage(
        [Description("The full URL of the web page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var html = await http.GetStringAsync(url, cancellationToken);
            var text = StripHtml(html);
            return text.Length > 3000 ? text[..3000] + "\n... [truncated]" : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch '{url}': {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        var text = Regex.Replace(html, @"<script[^>]*>.*?</script>", "",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<style[^>]*>.*?</style>", "",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<[^>]+>", " ");
        text = WebUtility.HtmlDecode(text);
        return Regex.Replace(text, @"\s+", " ").Trim();
    }
}

sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Saves a research note with a title and detailed content. Use this to record key findings.")]
    public string AddNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("Detailed content including facts, data, and source URLs")] string content)
    {
        _notes.Add((title, content));
        return $"Note '{title}' saved. ({_notes.Count} total)";
    }

    [Description("Retrieves all saved research notes for review before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note {i + 1}: {n.Title} ---\n{n.Content}"));
    }

    public void Clear() => _notes.Clear();
}

